const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const { language, setLanguage, t } = useLanguage();

  const toggleLanguage = () => {
    setLanguage(language === 'zh' ? 'en' : 'zh');
    setIsOpen(false);
  };

  const navLinks = [
    { name: t.navbar.features, href: '#features' },
    { name: t.navbar.protocols, href: '#protocols' },
    { name: t.navbar.process, href: '#process' },
    { name: t.navbar.pricing, href: '#pricing' },
  ];

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    e.preventDefault();
    setIsOpen(false);

    const targetId = href.substring(1);
    const element = document.getElementById(targetId);

    if (element) {
      const headerOffset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.scrollY - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  return (
    <nav className="fixed w-full z-50 glass">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <div className="flex-shrink-0 flex items-center gap-1">
            <span className="text-xl font-bold text-slate-900 tracking-tight">ChironMotion</span>
            <span 
                className="text-xl font-bold tracking-tight text-transparent bg-clip-text animate-gradient-text drop-shadow-[0_0_5px_rgba(0,174,239,0.3)]"
                style={{
                  backgroundImage: 'linear-gradient(to right, #020079, #0033CC, #00AEEF, #84E1BC, #00CC88, #020079)',
                  backgroundSize: '200% auto'
                }}
            >
              AI
            </span>
          </div>

          <div className="hidden md:block">
            <div className="flex items-baseline space-x-8">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={(e) => handleNavClick(e, link.href)}
                  className="text-slate-600 hover:text-brand-blue transition-colors px-3 py-2 rounded-md text-sm font-medium cursor-pointer"
                >
                  {link.name}
                </a>
              ))}
            </div>
          </div>

          <div className="hidden md:flex items-center gap-4">
             <button 
              onClick={toggleLanguage}
              className="flex items-center gap-1 text-slate-500 hover:text-brand-blue transition-colors text-sm font-medium"
            >
              <Globe size={18} />
              <span>{language === 'zh' ? 'EN' : '中'}</span>
            </button>

            <a 
              href={APP_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="bg-brand-blue hover:bg-blue-800 text-white px-4 py-2 rounded-full text-sm font-medium transition-all shadow-[0_4px_14px_0_rgba(0,51,204,0.39)] hover:shadow-[0_6px_20px_rgba(0,51,204,0.23)]"
            >
              {t.navbar.cta}
            </a>
          </div>

          <div className="-mr-2 flex md:hidden items-center gap-4">
             <button 
              onClick={toggleLanguage}
              className="flex items-center gap-1 text-slate-500 hover:text-brand-blue transition-colors text-sm font-medium"
            >
              <Globe size={18} />
              <span>{language === 'zh' ? 'EN' : '中'}</span>
            </button>
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-slate-600 hover:text-brand-blue hover:bg-slate-100 focus:outline-none"
            >
              {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="md:hidden glass border-t border-slate-100">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3 bg-white">
            {navLinks.map((link) => (
              <a
